#sse-cookie-banner{position:fixed;left:0;right:0;bottom:0;z-index:2147483647;padding:16px;pointer-events:none;font-family:ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,Noto Sans,sans-serif;line-height:1.5;text-align:left}
#sse-cookie-banner *{box-sizing:border-box;margin:0;padding:0;border:0;vertical-align:baseline;background:transparent}
#sse-cookie-banner a{color:inherit;text-decoration:none}
#sse-cookie-banner .sse-cookie-shell{pointer-events:auto;width:100%;max-width:980px;margin:0 auto;display:flex!important;gap:16px!important;align-items:center!important;justify-content:space-between!important;flex-wrap:wrap!important;padding:16px 18px!important;background:var(--sse-cookie-bg);color:var(--sse-cookie-fg);border:1px solid var(--sse-cookie-border);box-shadow:var(--sse-cookie-shadow)}
#sse-cookie-banner .sse-cookie-side{display:flex;align-items:center;gap:12px;min-width:240px;flex:1 1 420px}
#sse-cookie-banner .sse-cookie-icon{width:34px!important;height:34px!important;min-width:34px;border-radius:12px;display:grid;place-items:center;background:rgba(37,99,235,.12);font-size:18px}
#sse-cookie-banner .sse-cookie-head{display:flex!important;flex-direction:column!important;gap:4px!important}
#sse-cookie-banner .sse-cookie-title{font-weight:800;font-size:16px;line-height:1.2;margin:0 0 2px 0!important;color:var(--sse-cookie-fg)}
#sse-cookie-banner .sse-cookie-text{font-size:13.5px;line-height:1.35;margin:0!important;color:var(--sse-cookie-muted)}
#sse-cookie-banner .sse-cookie-actions{display:flex!important;gap:10px!important;align-items:center!important;flex-wrap:wrap;flex-shrink:0}
#sse-cookie-banner .sse-cookie-btn{appearance:none;border:0;cursor:pointer;border-radius:999px;padding:10px 14px!important;font-weight:800;font-size:13px!important;line-height:1!important;background:var(--sse-cookie-accent);color:#fff!important;box-shadow:0 10px 24px rgba(0,0,0,.18);transition:transform .08s ease, filter .12s ease;white-space:nowrap}
#sse-cookie-banner .sse-cookie-btn:hover{filter:brightness(1.06)}
#sse-cookie-banner .sse-cookie-btn:active{transform:translateY(1px)}
#sse-cookie-banner .sse-cookie-link{font-weight:800;font-size:13px;text-decoration:underline!important;text-underline-offset:2px;opacity:.9;white-space:nowrap;color:var(--sse-cookie-fg)!important}
#sse-cookie-banner .sse-cookie-link:hover{opacity:1}
@media (max-width:600px){
  #sse-cookie-banner{padding:12px}
  #sse-cookie-banner .sse-cookie-shell{padding:14px!important;flex-direction:column!important;align-items:flex-start!important}
  #sse-cookie-banner .sse-cookie-side{min-width:0;flex:1 1 100%;width:100%}
  #sse-cookie-banner .sse-cookie-actions{width:100%;justify-content:flex-start;margin-top:8px}
  #sse-cookie-banner .sse-cookie-btn{width:100%;justify-content:center}
}

/* Layout Skins */
#sse-cookie-banner[data-layout="0"] .sse-cookie-shell{border-radius:18px}
#sse-cookie-banner[data-layout="1"] .sse-cookie-shell{border-radius:22px;border-width:2px}
#sse-cookie-banner[data-layout="2"] .sse-cookie-shell{border-radius:18px;background:linear-gradient(135deg, rgba(37,99,235,.10), rgba(37,99,235,.03)), var(--sse-cookie-bg)}
#sse-cookie-banner[data-layout="3"] .sse-cookie-shell{border-radius:999px}
#sse-cookie-banner[data-layout="4"] .sse-cookie-shell{border-radius:22px;background:rgba(255,255,255,.72);backdrop-filter:saturate(1.2) blur(10px)}
@media (prefers-color-scheme:dark){#sse-cookie-banner[data-layout="4"] .sse-cookie-shell{background:rgba(11,18,32,.72)}}
#sse-cookie-banner[data-layout="5"] .sse-cookie-shell{border-radius:16px;box-shadow:none;border-left:0;border-right:0;border-bottom:0;border-top:3px solid rgba(37,99,235,.55)}
#sse-cookie-banner[data-layout="6"] .sse-cookie-shell{border-radius:18px;position:relative}
#sse-cookie-banner[data-layout="6"] .sse-cookie-shell:before{content:"";position:absolute;left:12px;top:12px;bottom:12px;width:6px;border-radius:999px;background:var(--sse-cookie-accent);opacity:.85}
#sse-cookie-banner[data-layout="6"] .sse-cookie-side{padding-left:10px}
#sse-cookie-banner[data-layout="7"] .sse-cookie-shell{border-radius:22px;background:var(--sse-cookie-bg);box-shadow:0 10px 30px rgba(2,6,23,.16)}
#sse-cookie-banner[data-layout="7"] .sse-cookie-icon{background:var(--sse-cookie-accent);color:#fff}
#sse-cookie-banner[data-layout="8"] .sse-cookie-shell{border-radius:18px;transform:translateY(-4px)}
#sse-cookie-banner[data-layout="9"] .sse-cookie-shell{border-radius:18px;border:2px solid rgba(37,99,235,.45)}
</style></head>

