    color: inherit !important;
    
    display: block !important;
    width: 100% !important;
    max-width: 100% !important;
    padding: 12px 16px !important;
    border-radius: 4px !important;
    box-sizing: border-box !important;
    margin: 0 !important;
    outline: none;
    font-size: 16px !important;
    line-height: 1.5 !important;
    box-shadow: none !important;
    transition: all 0.2s ease;
}

/* Хак от белого фона автозаполнения */
form input:-webkit-autofill,
form input:-webkit-autofill:hover, 
form input:-webkit-autofill:focus, 
form textarea:-webkit-autofill {
    -webkit-transition: background-color 5000s ease-in-out 0s;
    transition: background-color 5000s ease-in-out 0s;
    -webkit-text-fill-color: inherit !important;
}

form input:focus, form textarea:focus {
    border-color: currentColor !important;
    background-color: rgba(255, 255, 255, 0.12) !important;
}

/* Красная рамка при ошибке */
form input.sse-is-invalid, form textarea.sse-is-invalid {
    border-color: #ff4d4d !important;
    background-color: rgba(255, 0, 0, 0.05) !important;
}

/* Лейблы */
form label {
    display: block !important;
    margin-bottom: 8px !important;
    font-weight: 600 !important;
    opacity: 0.95;
    color: inherit !important;
    font-size: 0.95em !important;
    line-height: 1.2 !important;
}

/* =========================================
   4. СООБЩЕНИЯ ОБ ОШИБКАХ (Красный текст)
   ========================================= */

/* Скрываем старые/битые сообщения темы */
form .srfm-error-message, form .error-message, form .wpcf7-not-valid-tip {
    display: none !important;
}

/* Наши новые, созданные JS сообщения */
.sse-js-error-message {
    color: #ff4d4d !important;
    font-size: 13px !important;
    margin-top: 6px !important;
    font-weight: normal !important;
    display: block !important;
    animation: sse-fade 0.3s ease;
    text-align: left !important;
}
@media (prefers-color-scheme: light) {
    .sse-js-error-message { color: #d32f2f !important; }
}
@keyframes sse-fade { from{opacity:0;transform:translateY(-3px)} to{opacity:1;transform:translateY(0)} }

/* Кнопка */
form button[type="submit"], form input[type="submit"] {
    cursor: pointer !important;
    margin-top: 10px !important;
}
form button[aria-busy="true"], form input[aria-busy="true"] {
    opacity: 0.6; cursor: wait !important; pointer-events: none;
}</style>
<script>(function(){
    function r(f){if(document.readyState!=='loading'){f()}else{document.addEventListener('DOMContentLoaded',f)}}
    
    // Переводы
    function L(){var l=(document.documentElement.getAttribute('lang')||'').toLowerCase();if(l)return l;var c=(window.SSEBE_CONFIG||{});if(c.wp_lang)return (c.wp_lang+'').toLowerCase();var n=(navigator.language||(navigator.languages&&navigator.languages[0])||'').toLowerCase();return n||'en'}
    function M(lang){lang=(lang||'').toLowerCase();var b=lang.split('-')[0];var t={'en':'Thank you! Your message has been sent.','cs':'Děkujeme! Vaše zpráva byla odeslána.','sk':'Ďakujeme! Vaša správa bola odoslaná.','ru':'Спасибо! Ваша заявка отправлена.','uk':'Дякуємо! Ваше повідомлення надіслано.','pl':'Dziękujemy! Twoja wiadomość została wysłana.','de':'Danke! Ihre Nachricht wurde gesendet.','fr':'Merci ! Votre message a été envoyé.','es':'¡Gracias! Tu mensaje ha sido enviado.','it':'Grazie! Il tuo messaggio è stato inviato.','ja':'ありがとうございます。メッセージが送信されました。','tr':'Teşekkürler! Mesajınız gönderildi.','pt':'Obrigado! A sua mensagem foi enviada.','pt-br':'Obrigado! Sua mensagem foi enviada.','bg':'Благодарим! Вашето съобщение беше изпратено.','hu':'Köszönjük! Üzenete elküldve.','el':'Ευχαριστούμε! Το μήνυμά σας στάλθηκε.','da':'Tak! Din besked er blevet sendt.','ga':'Go raibh maith agat! Seoladh do theachtaireacht.','nl':'Bedankt! Je bericht is verzonden.','ro':'Mulțumim! Mesajul tău a fost trimis.','fi':'Kiitos! Viestisi on lähetetty.','sr':'Hvala! Vaša poruka je poslata.','sv':'Tack! Ditt meddelande har skickats.','hr':'Hvala! Vaša poruka je poslana.','sl':'Hvala! Vaše sporočilo je bilo poslano.','th':'ขอบคุณ! ส่งข้อความของคุณแล้ว','id':'Terima kasih! Pesan Anda telah terkirim.','zh':'谢谢！您的消息已发送。','zh-cn':'谢谢！您的消息已发送。','ms':'Terima kasih! Mesej anda telah dihantar.','ko':'감사합니다! 메시지가 전송되었습니다.','uz':'Rahmat! Xabaringiz yuborildi.','tg':'Ташаккур! Паёми шумо фиристода шуд.','kk':'Рақмет! Хабарыңыз жіберілді.','es-ve':'¡Gracias! Tu mensaje ha sido enviado.','es-pe':'¡Gracias! Tu mensaje ha sido enviado.','es-cl':'¡Gracias! Tu mensaje ha sido enviado.','sv-se':'Tack! Ditt meddelande har skickats.','de-ch':'Danke! Ihre Nachricht wurde gesendet.'};return t[lang]||t[b]||t['en']}

    // Тексты ошибок
    var ERR_REQ = "This field is required.";
    var ERR_EMAIL = "Please enter a valid email address.";

    function validateForm(form) {
        var isValid = true;
        var inputs = form.querySelectorAll('input, textarea, select');
        
        inputs.forEach(function(input) {
            // 1. Очистка старых ошибок
            input.classList.remove('sse-is-invalid');
            
            // Ищем нашего непосредственного родителя (обертку инпута)
            var parent = input.parentElement; 
            
            // Удаляем старое сообщение об ошибке, если оно есть в этом родителе
            // или является следующим соседом (в зависимости от верстки)
            var nextEl = input.nextElementSibling;
            if (nextEl && nextEl.classList.contains('sse-js-error-message')) {
                nextEl.remove();
            }

            // 2. Логика проверки
            var isRequired = input.hasAttribute('required') || 
                             input.getAttribute('data-required') === 'true' || 
                             input.getAttribute('aria-required') === 'true';
            
            var val = input.value.trim();
            var errorText = "";

            if (isRequired && !val) {
                errorText = ERR_REQ;
            } else if (val && input.type === 'email') {
                // Валидация Email (наличие @ и точки)
                if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) {
                    errorText = ERR_EMAIL;
                }
            }

            // 3. Вывод ошибки
            if (errorText) {
                isValid = false;
                input.classList.add('sse-is-invalid'); // Для красной рамки
                
                var msg = document.createElement('div');
                msg.className = 'sse-js-error-message';
                msg.textContent = errorText;
                
                // Вставляем ошибку СРАЗУ ПОСЛЕ инпута в тот же контейнер
                // Это самое безопасное место
                if (input.nextSibling) {
                    parent.insertBefore(msg, input.nextSibling);
                } else {
                    parent.appendChild(msg);
                }
            }
        });

        return isValid;
    }

    r(function(){
        var c=(window.SSEBE_CONFIG||{});
        document.querySelectorAll('form').forEach(function(fm){
            if(fm.dataset&&fm.dataset.sseNoStub=='1')return;
            var role=(fm.getAttribute('role')||'').toLowerCase();
            if(role==='search'||/search/i.test(fm.className||'')||/commentform/i.test(fm.id||''))return;
            
            // Убиваем нативную валидацию
            fm.setAttribute('novalidate', 'true');

            // Чистим мусор WP
            ['_wpnonce','_wpcf7','_elementor_form_id'].forEach(function(n){var el=fm.querySelector('input[name="'+n+'"]');if(el)el.remove()});
            
            fm.addEventListener('submit',function(e){
                e.preventDefault();
                e.stopImmediatePropagation();

                // Валидация
                if (!validateForm(fm)) {
                    // Если ошибка - пытаемся проскроллить к ней
                    var firstError = fm.querySelector('.sse-is-invalid');
                    if(firstError) {
                        // Небольшая задержка для плавности
                        setTimeout(function(){
                            firstError.scrollIntoView({behavior: "smooth", block: "center"});
                            firstError.focus();
                        }, 100);
                    }
                    return false;
                }

                // Успех
                var d=parseInt(fm.dataset.delay||c.delay_ms||800,10);
                var s=fm.dataset.success||c.success_text||M(L());
                var u=fm.dataset.redirect||c.redirect_url||'';
                
                var b=fm.querySelector('button[type="submit"], input[type="submit"]');
                if(b){
                    if(b.tagName==='INPUT')b.value='…';
                    else b.innerHTML='… <span class="sse-spinner"></span>';
                    b.disabled=true;
                }
                
                setTimeout(function(){
                    if(u){window.location.href=u;return}
                    var box=document.createElement('div');
                    box.className='sse-form-success';
                    box.textContent=s;
                    fm.replaceWith(box);
                    try{box.focus()}catch(e){}
                },isNaN(d)?800:d);
            },true)
        })
    })
})();</script>
<script>window.SSEBE_CONFIG=window.SSEBE_CONFIG||{};Object.assign(window.SSEBE_CONFIG,{"anchor_home":"\/","anchor_remove_mode":"hide"});</script>
<script>(function(){
  function ready(fn){ if(document.readyState!=='loading'){fn()} else {document.addEventListener('DOMContentLoaded', fn)} }
  function sameOrigin(url){ try{ var u=new URL(url, location.href); return u.origin===location.origin; } catch(e){ return false; } }
  function normalizePath(p){ if (!p) return ''; return p.replace(/\/index\.html?$/i,'').replace(/\/+#.*$/,''); }
  function isAnchorForThisOrHome(a, home){
    var href = (a.getAttribute('href')||'').trim();
    if (!href || !href.includes('#')) return false;
    if (href[0] === '#') return true;
    try { var u=new URL(href, location.href); if(!sameOrigin(u.href)) return false;
      var path=normalizePath(u.pathname), here=normalizePath(location.pathname), hpath=normalizePath(home||'/');
      return (path===here || path==='' || path==='/' || path===hpath);
    } catch(e){ return /(^|\/)index\.html#/.test(href) || /^\/#/.test(href); }
  }
  function isAccordionControl(a){
    var cls = (a.className||'').toLowerCase();
    if (/accordion|toggle|tab-title|tab\b|collaps(e|ible)|faq/.test(cls)) return true;
    if (a.getAttribute('role')==='button' || a.hasAttribute('aria-controls')) return true;
    var parent=a.closest('.elementor-accordion, .elementor-toggle, .accordion, [role="tablist"], .faq'); return !!parent;
  }
  ready(function(){
    var cfg=(window.SSEBE_CONFIG||{}), home=cfg.anchor_home||'/', mode=(cfg.anchor_remove_mode||'hide').toLowerCase();
    document.querySelectorAll('a[href*="#"]').forEach(function(a){
      if (a.dataset && (a.dataset.sseNoAnchor==='1' || a.dataset.sseNoAnchor===1)) return;
      if (isAccordionControl(a)) return;
      if (!isAnchorForThisOrHome(a, home)) return;
      if (mode==='unwrap'){ var span=document.createElement('span'); span.innerHTML=a.innerHTML; span.className=(a.className||'').trim(); a.parentNode.replaceChild(span,a); }
      else { var li=a.closest('li'); if(li&&li.parentNode){li.parentNode.removeChild(li);} else if(a.parentNode){a.parentNode.removeChild(a);} }
    });
  });
})();</script>
<style>.elementor-tab-content,.elementor-accordion-content,.elementor-toggle-content,.accordion-collapse,.accordion-body{display:none}.sse-faq-open{display:block!important}</style>
<script>(function(){
  function ready(fn){ if(document.readyState!=='loading'){fn()} else {document.addEventListener('DOMContentLoaded', fn)} }
  function makeButton(el){el.setAttribute('role','button'); el.setAttribute('tabindex','0'); if(!el.hasAttribute('aria-expanded')) el.setAttribute('aria-expanded','false'); el.addEventListener('keydown', function(e){ if (e.key==='Enter' || e.key===' ') { e.preventDefault(); el.click(); } });}
  function toggleEl(control, content){var open = content.classList.toggle('sse-faq-open'); content.style.display = open ? 'block' : 'none'; control.setAttribute('aria-expanded', open ? 'true':'false'); control.classList.toggle('sse-faq-open', open);}
  ready(function(){
    document.querySelectorAll('.elementor-accordion, .elementor-toggle').forEach(function(acc){
      acc.querySelectorAll('.elementor-accordion-item, .elementor-toggle-item').forEach(function(item){
        var control = item.querySelector('.elementor-tab-title, .elementor-accordion-title, .elementor-toggle-title, a.elementor-accordion-title, a.elementor-toggle-title');
        var content = item.querySelector('.elementor-tab-content, .elementor-accordion-content, .elementor-toggle-content, .elementor-tab-content');
        if (!control || !content) return;
        if (control.tagName === 'A'){ control.setAttribute('href', 'javascript:void(0)'); }
        makeButton(control);
        if (!content.style.display) content.style.display = 'none';
        control.addEventListener('click', function(e){ e.preventDefault(); toggleEl(control, content); });
      });
    });
    document.querySelectorAll('.accordion .accordion-item').forEach(function(item){
      var btn = item.querySelector('.accordion-button, [data-bs-toggle="collapse"]');
      var body = item.querySelector('.accordion-collapse, .accordion-body');
      if (!btn || !body) return;
      makeButton(btn);
      if (!body.style.display) body.style.display = 'none';
      btn.addEventListener('click', function(e){ e.preventDefault(); toggleEl(btn, body); });
    });
    document.querySelectorAll('[data-faq], .faq, .faq-list').forEach(function(wrap){
      wrap.querySelectorAll('.faq-item').forEach(function(item){
        var q = item.querySelector('.faq-q, .question, .faq-title, h3, h4');
        var a = item.querySelector('.faq-a, .answer, .faq-content, p + div, .content');
        if (q && a){ makeButton(q); if (!a.style.display) a.style.display = 'none'; q.addEventListener('click', function(){ toggleEl(q, a); }); }
      });
    });
  });
})();</script>
	

